[7664]={"白色迅猛龍",nil,nil,nil,nil,"您能選擇下列奬勵中的一個：\n\n迅捷藍色迅猛龍迅捷綠色迅猛龍迅捷橘色迅猛龍"},
[7665]={"紅色迅猛龍",nil,nil,nil,nil,"您能選擇下列奬勵中的一個：\n\n迅捷藍色迅猛龍迅捷綠色迅猛龍迅捷橘色迅猛龍"},
[7666]={"重回屍骨儲藏所",nil,nil,nil,nil,"您會收到：\n\n預言水晶球"},
[7667]={"蒐集材料","如果你願意幫助奧格瑪智慧谷的薩格尼，就將一顆艾澤拉斯鑽石和一顆原始黑鑽石交給他。","<name>，這是一件我希望能得到你幫助的事情，一件重要的事情……請允許我解釋一下。\n\n在羅德隆的通靈學院中有一個被稱為屍骨儲藏所的房間。我要製造一個能夠洞穿那個房間中的邪惡力量的裝置，因此我需要兩塊鑽石:一塊艾澤拉斯鑽石和一塊原始黑鑽石。我知道這兩樣東西都不是那麼容易得到的，而且我自己沒有辦法得到。\n\n你能幫我拿來這兩樣東西嗎?您會收到：\n\n完成任務後，你將獲得：\n\n",nil,nil,"您會收到：\n\n"},
[7668]={"達克雷爾的威脅","在通靈學院的屍骨儲藏所地下室中心使用預言水晶球，這樣將會召來一些靈魂，你必須與它們交戰。將這些靈魂擊敗，死亡騎士達克雷爾就會出現。\n\n擊敗達克雷爾，將他的頭顱交給奧格瑪智慧谷的薩格尼。","死亡騎士達克雷爾掌管著通靈學院的屍骨儲藏所。他威脅要讓靈魂世界徹底扭曲，以達到自己的目的，我們必須阻止他！這就是你需要水晶球的原因。\n\n在屍骨儲藏所地下室的中心使用預言水晶球來召喚達克雷爾的靈魂爪牙。將那些靈魂擊敗，這時死亡騎士就會出現，<name>，把他的頭顱交給我！只有他的死亡才能讓靈魂世界免受傷害！您會收到：\n\n",nil,nil,"您會收到：\n\n潛能頭盔"},
[7669]={"重回屍骨儲藏所",nil,nil,nil,nil,"您會收到：\n\n預言水晶球"},
[7670]={"格雷森·破影者領主","與暴風城教堂區的格雷森·破影者領主談話。","這個偉大的時刻終於到來了，<name>，接下來你就將獲得你渴望已久的東西─你的戰馬。\n\n去和暴風城教堂區的格雷森·破影者領主談談吧。他將指引你完成必需的任務，令你獲得一匹聖騎士最可信任的坐騎。\n\n我祝你在這次試煉中好運，為了聖光而戰，我的<兄弟/姐妹>!您會收到：\n\n完成任務後，你將獲得：\n\n",nil,nil,"您會收到：\n\n"},
