[7824]={"捐獻符文布",nil,nil,nil,nil,"您會收到：\n\n"},
[7825]={"更多的符文布"},
[7826]={"捐獻毛料",nil,nil,nil,nil,"您會收到：\n\n"},
[7827]={"捐獻絲綢",nil,nil,nil,nil,"您會收到：\n\n"},
[7828]={"銀鬃捕獵者","辛特蘭惡齒村的獵人馬克霍爾要求你去殺掉10頭銀鬃捕獵者和10頭銀鬃嗥狼。完成任務之後就回到他那裡覆命。\n\n馬克霍爾說過那些狼都躲在辛特蘭的野外。","許多勇敢的食人妖都在辛特蘭的森林中失蹤了，<race>。銀鬃狼對我們的獵人來說是最大的威脅。它們靜靜地隱藏在灌木叢中，當時機成熟之後就發起突然襲擊。\n\n我們一定要阻止這種殘忍的行為!\n\n你必須和銀鬃狼一樣思考。我們要以牙還牙，獵捕它們!把它們全都殺掉!您會收到：\n\n完成任務後，你將獲得：\n\n",nil,nil,"您會收到：\n\n"},
[7829]={"野蠻的梟獸","辛特蘭惡齒村的獵人馬克霍爾要求你去殺掉20頭野蠻的梟獸。完成任務之後就回到他那裡覆命。\n\n馬克霍爾說過那些野蠻的梟獸都躲在辛特蘭的野外。","辛特蘭地區最令人討厭的生物之一就是那些野蠻的梟獸。很多勇敢的惡齒戰士都倒在了那些野獸的利爪和尖嘴之下。\n\n幹掉你看到的每個野蠻的梟獸，<race>。當你把它們殺得血流成河的時候就回到我這裡來，你的貢獻一定會得到我們的讚賞。您會收到：\n\n完成任務後，你將獲得：\n\n",nil,nil,"您會收到：\n\n"},
[7830]={"死者的復仇","辛特蘭惡齒村的獵戶馬克霍爾要求你殺掉一頭翱翔的鋒喙獅鷲獸，並將它的獅鷲獸長羽拿回去交給他。\n\n馬克霍爾說過那些翱翔的鋒喙獅鷲獸就躲在辛特蘭的野外。","現在蠻錘部族訓練的獅鷲獸正在肆意屠殺食人妖。這真是太可怕了，但是我知道不久之後正義就將得到伸張。\n\n現在我需要派你去清除那些成年的獅鷲獸首領，也就是那種翱翔的獅鷲獸。\n\n殺掉它們中的一個，然後把它的羽毛交給我。您會收到：\n\n完成任務後，你將獲得：\n\n",nil,nil,"您會收到：\n\n"},
