[7941]={"更多的護甲片",nil,nil,nil,nil,"您會收到：\n\n暗月馬戲團獎品券"},
[7942]={"更多的瑟銀零件",nil,nil,nil,nil,"您會收到：\n\n暗月馬戲團獎品券"},
[7943]={"更多蝙蝠眼",nil,nil,nil,nil,"您會收到：\n\n暗月馬戲團獎品券"},
[7944]={"財富等著你……","到貧瘠之地的哀嚎洞穴中去尋找你的財寶吧。","「哀嚎洞穴中的財寶正等著你。」\n\n你撫摸著手中的占卜，感到一絲暖意。你緊緊地握住它，眼前浮現出了位於貧瘠之地十字路口西南方的一處洞穴的影像。你專注地觀察著，發現蜿蜒的道路盡頭是一道發光的門……通往洞穴中心的門。你穿過大門，不知從哪兒冒出了一個奇怪的箱子。您會收到：\n\n",nil,nil,"您會收到：\n\n神秘的帶鎖箱"},
[7945]={"財富等著你……","到莫高雷的白鬃石去尋找你的財寶吧。","「白鬃石外的財寶正等著你。」\n\n你撫摸著手中的占卜，感到一絲暖意。你緊緊地握住它，眼前浮現出莫高雷白鬃石的影像。你專注地觀察著，發現洞穴入口附近有一塊樹樁。您會收到：\n\n",nil,nil,"您會收到：\n\n神秘的帶鎖箱"},
[7946]={"啾啾的蛋",nil,nil,nil,nil,"您會收到：\n\n加布林蛙卵"},
[7961]={"Waskily Wabbits!","Kill 5 rabbits and return to Jon LeCraft by the forge on Designer Island.","These rabbits are breeding uncontrollably.  Something must be done!\n\nHelp us <name>, you're our only hope.您會學到：\n\n",nil,nil,"您會學到：\n\n馴獸教程"},
