[8104]={"卡亞羅的珠寶",nil,nil,nil,nil,"您會收到：\n\n卡亞羅的珠寶"},
[8105]={"阿拉希盆地之戰!","進攻礦坑、伐木場、鐵匠鋪和農場，然後向避難谷地的奧斯萊特元帥覆命。","<name>，在阿拉希盆地的戰鬥是為了資源和領土而進行的戰鬥。這個地區作戰的關鍵是確保我們軍隊稀有物資和補給的順暢運作。我命令你去攻擊距離我們在阿拉希盆地中的基地最遠的戰略設施。\n\n當農場、礦坑、伐木場或鐵匠舖被敵人佔據時，攻擊這些設施，找到敵人的旗幟然後把它拔掉!\n\n當你奪回這四個點之後再回到我這裡。您會收到：\n\n完成任務後，你將獲得：\n\n",nil,nil,"您會收到：\n\n"},
